INSERT INTO `movies` (`MovieID`, `Title`, `Description`, `Duration`, `CoverPhoto`, `Director`, `Actor1`, `Actor2`, `ReleaseYear`, `Genre`, `ShowTime`) VALUES
(1, 'Ο Εξορκιστής: Πιστός', 'Μετά τον τραγικό θάνατο της εγκύου συζύγου του στον φονικό Σεισμό στην Αϊτή πριν από 12 χρόνια, ο Βίκτορ Φίλντινγκ έχει μεγαλώσει μόνος του την κόρη τους Άντζελα. Αλλά όταν η Άντζελα και η φίλη της Κάθριν εξαφανίζονται στο δάσος και επιστρέφουν τρεις μέρες μετά χωρίς καμία ανάμνηση του τι συνέβη, ξεκινάει μία σειρά από αλυσιδωτά γεγονότα που θα αναγκάσουν τον Βίκτορ να αντιμετωπίσει το απόλυτο κακό και, μέσα στην απόγνωση και τον τρόμο του, να αναζητήσει το μοναδικό άτομο που έχει βιώσει κάτι αντίστοιχο', 111, , 'David Gordon Green', 'Ellen Burstyn', 'Jennifer Nettles', 2023, 'ΘΡΙΛΕΡ', '01:47:00');
INSERT INTO `movies` (`MovieID`, `Title`, `Description`, `Duration`, `CoverPhoto`, `Director`, `Actor1`, `Actor2`, `ReleaseYear`, `Genre`, `ShowTime`) VALUES
(2, 'ΜΥΣΤΗΡΙΟ ΣΤΗ ΒΕΝΕΤΙΑ\r\nHAUNTING IN VENICE', 'Ο θρυλικός ντετέκτιβ Ηρακλής Πουαρό (Kenneth Branagh) έχει αποσυρθεί από την ενεργό δράση και ζει στην απόκοσμη, μεταπολεμική Βενετία. Όλα αλλάζουν όταν τον επισκέπτεται η Ariadne Oliver (Tina Fey), η πιο διάσημη συγγραφέας μυστηρίου, που ισχυρίζεται ότι έχει κάτι να μοιραστεί μαζί του και του υπόσχεται ότι δεν πρόκειται για έγκλημα. Ο Πουαρό παρασύρεται και συμμετέχει σε μία σεάνς με φόντο ένα παρηκμασμένο, στοιχειωμένο παλάτι που ανήκει στη διάσημη τραγουδίστρια όπερας Rowena Drake (Kelly Reilly). Όταν ένας από τους συμμετέχοντες βρεθεί δολοφονημένος, όλοι θεωρούνται ύποπτοι και ο Βέλγος ντετέκτιβ βυθίζεται σε έναν νοσηρό κόσμο που κρύβει πολλά μυστικά.', 103, , 'Kenneth Branagh.', 'Kenneth Branagh', 'Kelly Reilly', 2023, 'ΘΡΙΛΕΡ ΜΥΣΤΗΡΙΟΥ.', '15:20:00');
INSERT INTO `movies` (`MovieID`, `Title`, `Description`, `Duration`, `CoverPhoto`, `Director`, `Actor1`, `Actor2`, `ReleaseYear`, `Genre`, `ShowTime`) VALUES
(3, 'THE MARVELS', 'Στην ταινία The Marvels των Marvel Studios, η Carol Denvers (Captain Marvel) έχει επανακτήσει την ταυτότητά της από τους τυραννικούς Kree και έχει πάρει και την εκδίκησή της από την Υπέρτατη Νοημοσύνη. Αλλά οι επιπτώσεις των πράξεων την έχουν φορτώσει με μεγάλες ευθύνες. Όταν τα καθήκοντα της την οδηγούν σε μία ανωμαλία στο γαλαξία που συνδέεται με τους Kree, οι δυνάμεις της μπερδεύονται με αυτές της μεγαλύτερης θαυμάστρια της, Kamala Khan, γνωστής κι ως Ms. Marvel, αλλά και της ανιψιάς της, Captain Monica Rambeau, αστροναύτη για την S.A.B.E.R. Αυτή η απρόσμενη ομάδα, ως “The Marvels”, θα μάθει να δουλεύει μαζί, σε αρμονία, με στόχο τη σωτηρία του σύμπαντος.', 105, , 'Nia DaCosta.', 'Brie Larson', 'Zawe Ashton', 2023, 'ACTION ΦΑΝΤΑΣΙΑΣ', '15:53:00');
INSERT INTO `movies` (`MovieID`, `Title`, `Description`, `Duration`, `CoverPhoto`, `Director`, `Actor1`, `Actor2`, `ReleaseYear`, `Genre`, `ShowTime`) VALUES
(4, 'ΑΚΟΥ ΠΟΙΟΣ ΜΙΛΑΕΙ', 'Ο Φώτης (Μελέτης Ηλίας) είναι σε αδιέξοδο τόσο σε προσωπικό όσο και σε επαγγελματικό επίπεδο. Ένας life coach, αυτό είναι το επάγγελμά του, που έχει χάσει τον προσανατολισμό του. Οι συνεδρίες, που κάποτε επαγγελματικά τον γέμιζαν, δεν του προσφέρουν πλέον την ίδια εσωτερική ικανοποίηση ενώ και στην προσωπική του ζωή έχει απομονωθεί πλήρως. Σε αυτή την κρίσιμη καμπή για τον εαυτό του και την καριέρα του, θα αναλάβει δράση μία γνώριμη σε αυτόν φωνή που ακούγεται μόνο μέσα στο μυαλό του. Είναι η φωνή της συνείδησής του που προσπαθεί να τον κάνει να ζήσει τη ζωή του. Θα καταφέρει ο Φώτης να βρει ξανά τον… Φώτη και τον έρωτα πριν χαθούν όλα;.', 88, , 'Θοδωρής Νιάρχος. Green', 'Μελέτης Ηλίας', 'Δημήτρης Μακαλιάς', 2023, 'COMEDY', '21:15:00');
INSERT INTO `movies` (`MovieID`, `Title`, `Description`, `Duration`, `CoverPhoto`, `Director`, `Actor1`, `Actor2`, `ReleaseYear`, `Genre`, `ShowTime`) VALUES
(5, 'ΟΙ ΔΟΛΟΦΟΝΟΙ ΤΟΥ ΑΝΘΙΣΜΕΝΟΥ ΦΕΓΓΑΡΙΟΥ\r\nKILLERS OF THE FLOWER MOON', 'Στην Αμερική των αρχών του 20ου αιώνα, το πετρέλαιο αποφέρει αμύθητα πλούτη στη φυλή των Όσεϊτζ, που γίνονται από τους πιο πλούσιους ανθρώπους στον κόσμο μέσα σε μία στιγμή. Ο αμύθητος πλούτος των αυτόχθονων Αμερικανών προσελκύει παρείσακτους λευκούς που χειραγωγούν, εκβιάζουν και κλέβουν τις περιουσίες των Όσεϊτζ για να καταλήξουν σε δολοφονίες.', 206, , 'Martin Scorsese', 'Leonardo DiCaprio', 'Robert De Niro', 2023, 'DRAMA', '20:00:00');
INSERT INTO `movies` (`MovieID`, `Title`, `Description`, `Duration`, `CoverPhoto`, `Director`, `Actor1`, `Actor2`, `ReleaseYear`, `Genre`, `ShowTime`) VALUES
(6, 'MAY DECEMBER', 'Είκοσι χρόνια μετά το σκάνδαλο που προκάλεσε το ρομάντζο της τότε 36χρονης Γκρέισι (Τζούλιαν Μουρ) και του 13χρονου Τζος (Τσαρλς Μέλτον), το ζευγάρι ζει μια φαινομενικά ειδυλλιακή προαστιακή ζωή. Η οικογενειακή τους γαλήνη θα διαταραχθεί απότομα από την έλευση της Ελίζαμπεθ (Νάταλι Πόρτμαν), μιας δημοφιλούς ηθοποιού που θέλει να κάνει έρευνα για τον επερχόμενο ρόλο της ως Γκρέισι. Όσο η Ελίζαμπεθ βυθίζεται στην καθημερινότητα του ζευγαριού, η άβολη πραγματικότητα του σκανδάλου αποκαλύπτεται, φέρνοντας στην επιφάνεια καταπιεσμένα συναισθήματα. Στο «MayDecember», o Τοντ Χέινς («Κάρολ») εξερευνάει ένα από τα μεγαλύτερα ταλέντα του ανθρώπινου είδους: την κολοσσιαία άρνηση να κοιτάξουμε τον εαυτό μας..', 117, , 'Todd Haynes.', 'Natalie Portman', 'Chris Tenzis', 2023, 'DRAMA', '03:11:00');

